  "inlineSchema": "// Prisma schema for Spooler + Better Auth\n// learn more: https://better-auth.com/docs/concepts/database\n\ngenerator client {\n  provider = \"prisma-client-js\"\n  output   = \"../generated/prisma\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\nmodel User {\n  id            String    @id\n  name          String\n  email         String\n  emailVerified Boolean   @default(false)\n  image         String?\n  /// admin | user\n  role          String    @default(\"user\")\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @default(now()) @updatedAt\n  sessions      Session[]\n  accounts      Account[]\n\n  brands       Brand[]\n  locations    Location[]\n  filaments    Filament[]\n  spools       Spool[]\n  customFields CustomField[]\n\n  @@unique([email])\n  @@map(\"user\")\n}\n\nmodel Session {\n  id        String   @id\n  expiresAt DateTime\n  token     String\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  ipAddress String?\n  userAgent String?\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@unique([token])\n  @@map(\"session\")\n}\n\nmodel Account {\n  id                    String    @id\n  accountId             String\n  providerId            String\n  userId                String\n  user                  User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  accessToken           String?\n  refreshToken          String?\n  idToken               String?\n  accessTokenExpiresAt  DateTime?\n  refreshTokenExpiresAt DateTime?\n  scope                 String?\n  password              String?\n  createdAt             DateTime  @default(now())\n  updatedAt             DateTime  @updatedAt\n\n  @@map(\"account\")\n}\n\nmodel Verification {\n  id         String   @id\n  identifier String\n  value      String\n  expiresAt  DateTime\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @default(now()) @updatedAt\n\n  @@map(\"verification\")\n}\n\nmodel Brand {\n  id         String     @id @default(cuid())\n  name       String\n  /// Storefront / manufacturer website\n  websiteUrl String?\n  userId     String\n  user       User       @relation(fields: [userId], references: [id], onDelete: Cascade)\n  createdAt  DateTime   @default(now())\n  updatedAt  DateTime   @updatedAt\n  filaments  Filament[]\n\n  @@unique([userId, name])\n  @@index([userId])\n}\n\nmodel Material {\n  id              String     @id @default(cuid())\n  name            String     @unique\n  density         Float?\n  maxNozzleC      Int?\n  maxBedC         Int?\n  minNozzleC      Int?\n  minBedC         Int?\n  /// brass | stainless | hardened | ruby — preferred nozzle tip material\n  preferredNozzle String?\n  createdAt       DateTime   @default(now())\n  updatedAt       DateTime   @updatedAt\n  filaments       Filament[]\n}\n\nmodel Location {\n  id        String   @id @default(cuid())\n  name      String\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n  spools    Spool[]\n\n  @@unique([userId, name])\n  @@index([userId])\n}\n\n/// Product definition: brand + material + color (+ defaults)\n/// SOLID | GRADIENT | MULTI\nmodel Filament {\n  id                  String              @id @default(cuid())\n  userId              String\n  user                User                @relation(fields: [userId], references: [id], onDelete: Cascade)\n  brandId             String\n  brand               Brand               @relation(fields: [brandId], references: [id])\n  materialId          String\n  material            Material            @relation(fields: [materialId], references: [id])\n  colorMode           String              @default(\"SOLID\")\n  colorName           String?\n  diameterMm          Float               @default(1.75)\n  /// Nominal full filament weight used when opening a new spool\n  defaultWeightG      Int                 @default(1000)\n  /// Typical empty plastic spool tare (g); copied onto new spool instances\n  defaultEmptyWeightG Int?\n  /// Product page / store listing\n  productUrl          String?\n  notes               String?\n  /// How many replacement spools to buy; 0 = not on repurchase list\n  repurchaseQty       Int                 @default(0)\n  createdAt           DateTime            @default(now())\n  updatedAt           DateTime            @updatedAt\n  colors              FilamentColorStop[]\n  spools              Spool[]\n  customFieldValues   CustomFieldValue[]\n\n  @@index([userId])\n  @@index([userId, repurchaseQty])\n  @@index([materialId])\n  @@index([brandId])\n}\n\nmodel FilamentColorStop {\n  id         String   @id @default(cuid())\n  filamentId String\n  filament   Filament @relation(fields: [filamentId], references: [id], onDelete: Cascade)\n  hex        String\n  name       String?\n  position   Float\n  weight     Float?\n\n  @@index([filamentId])\n}\n\n/// Physical spool instance (weights, status, location, usage logs)\nmodel Spool {\n  id               String    @id @default(cuid())\n  userId           String\n  user             User      @relation(fields: [userId], references: [id], onDelete: Cascade)\n  filamentId       String\n  filament         Filament  @relation(fields: [filamentId], references: [id])\n  locationId       String?\n  location         Location? @relation(fields: [locationId], references: [id], onDelete: SetNull)\n  initialWeightG   Int\n  remainingWeightG Int\n  /// Empty plastic spool tare (g) for scale → filament math\n  emptyWeightG     Int?\n  /// sealed | open | empty | archived\n  status           String    @default(\"sealed\")\n  purchasedAt      DateTime?\n  priceCents       Int?\n  notes            String?\n  lastDriedAt      DateTime?\n  createdAt        DateTime  @default(now())\n  updatedAt        DateTime  @updatedAt\n  usages           Usage[]\n\n  @@index([userId])\n  @@index([userId, status])\n  @@index([filamentId])\n}\n\nmodel Usage {\n  id        String   @id @default(cuid())\n  spoolId   String\n  spool     Spool    @relation(fields: [spoolId], references: [id], onDelete: Cascade)\n  gramsUsed Int\n  note      String?\n  usedAt    DateTime @default(now())\n\n  @@index([spoolId])\n}\n\n/// TEXT | NUMBER | BOOLEAN | DATE | SELECT | MULTISELECT | URL\nmodel CustomField {\n  id         String             @id @default(cuid())\n  userId     String\n  user       User               @relation(fields: [userId], references: [id], onDelete: Cascade)\n  /// FILAMENT\n  entity     String             @default(\"FILAMENT\")\n  key        String\n  label      String\n  type       String\n  required   Boolean            @default(false)\n  /// JSON string array for SELECT / MULTISELECT\n  options    String?\n  sortOrder  Int                @default(0)\n  showInList Boolean            @default(false)\n  createdAt  DateTime           @default(now())\n  updatedAt  DateTime           @updatedAt\n  values     CustomFieldValue[]\n\n  @@unique([userId, entity, key])\n  @@index([userId, entity])\n}\n\nmodel CustomFieldValue {\n  id           String      @id @default(cuid())\n  fieldId      String\n  field        CustomField @relation(fields: [fieldId], references: [id], onDelete: Cascade)\n  filamentId   String\n  filament     Filament    @relation(fields: [filamentId], references: [id], onDelete: Cascade)\n  valueText    String?\n  valueNumber  Float?\n  valueBoolean Boolean?\n  valueDate    DateTime?\n\n  @@unique([fieldId, filamentId])\n  @@index([filamentId])\n}\n\n/// Singleton row (id = 1) tracking first-run setup\nmodel AppSetup {\n  id                Int       @id @default(1)\n  completed         Boolean   @default(false)\n  completedAt       DateTime?\n  installedDatasets String    @default(\"[]\")\n  createdAt         DateTime  @default(now())\n  updatedAt         DateTime  @updatedAt\n}\n",
